import base64
import pickle

def process_pubsub_messages(messages):
    for message in messages:
        # Decode the base64 encoded message data
        decoded_data = base64.b64decode(message['data'])
        
        # Deserialize the Python object using pickle
        python_object = pickle.loads(decoded_data)
        
        # Process the deserialized Python object
        process_python_object(python_object)

def process_python_object(obj):
    # Implement your processing logic here
    print(f"Processing object: {obj}")